def parse_nombre(raw):
    tokens = raw.split()
    if len(tokens) < 3:
        return {'status': 'review', 'raw': raw, 'given': raw, 'apellidos': None}
    return {
        'status': 'ok',
        'raw': raw,
        'given': ' '.join(tokens[:-2]),
        'apellidos': ' '.join(tokens[-2:]),
    }

print(parse_nombre('Madonna'))
print(parse_nombre('Ana María Quispe Huamán'))

def normalize_email(raw):
    s = raw.strip().casefold()
    if s.count('@') != 1 or any(ch.isspace() for ch in s):
        raise ValueError('review_error')
    local, domain = s.split('@', 1)
    if not local or not domain:
        raise ValueError('review_error')
    return s

print('ok', normalize_email('  A@B.COM '))
for bad in ['@b.com', 'a@@b.com', 'a b@c.com']:
    try:
        normalize_email(bad)
    except ValueError as e:
        print(bad, e)
print('ok', normalize_email('user+tag@example.com'))

def norm(s):
    return ' '.join(s.strip().casefold().split())

print(norm('  Juan  PEREZ ') == norm('juan perez'))

def token_jaccard(a, b):
    A, B = set(a.casefold().split()), set(b.casefold().split())
    if not A and not B:
        return 1.0
    if not A or not B:
        return 0.0
    return len(A & B) / len(A | B)

print(round(token_jaccard('Juan Perez', 'Juan P Perez'), 3))

